'use client';

import { motion } from 'framer-motion';

export default function About() {
  return (
    <motion.div
      initial={{ opacity: 0, y: 80, scale: 0.95 }}
      whileInView={{ opacity: 1, y: 0, scale: 1 }}
      transition={{ duration: 0.6, ease: 'easeOut' }}
      viewport={{ once: false, amount: 0.4 }}
    >
      <section className='relative min-h-screen flex items-center justify-center px-6 overflow-hidden'>
        <div className='max-w-7xl w-full flex flex-col md:flex-row items-center justify-between gap-12'>
          {/* 🔥 LEFT SIDE (TEXT) */}
          <motion.div
            initial={{ opacity: 0, x: -60 }}
            whileInView={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8 }}
            className='max-w-xl'
          >
            <h2 className='text-4xl sm:text-5xl md:text-6xl font-bold text-black/60'>
              About Me
            </h2>

            <p className='mt-6 text-base sm:text-lg md:text-xl text-gray/700 leading-relaxed'>
              I'm a{' '}
              <span className='text-primary font-semibold'>
                Full Stack Developer
              </span>{' '}
              focused on building scalable, real-world applications with clean
              and efficient code.
            </p>

            <p className='mt-4 text-gray/600'>
              I work with React, Node.js, and databases to create seamless user
              experiences and reliable backend systems.
            </p>

            <p className='mt-4 text-gray/600'>
              Currently improving my backend expertise and diving deeper into
              Java and system design.
            </p>

            {/* CTA */}
            <button className='mt-8 px-6 py-3 cursor-pointer  border border-black/20 rounded-xl hover:bg-black/5 transition'>
              Download Resume
            </button>
          </motion.div>

          {/* 🔥 RIGHT SIDE (SKILLS + STATS) */}
          <motion.div
            initial={{ opacity: 0, x: 60 }}
            whileInView={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8 }}
            className='w-full md:w-1/2 space-y-8'
          >
            {/* STATS */}
            <div className='flex gap-8 flex-wrap'>
              {[
                { value: '10+', label: 'Projects' },
                { value: '1+', label: 'Years Learning' },
                { value: '6+', label: 'Technologies' },
              ].map((item, index) => (
                <div key={index}>
                  <h3 className='text-2xl md:text-3xl font-bold text-primary'>
                    {item.value}
                  </h3>
                  <p className='text-gray/600 text-sm'>{item.label}</p>
                </div>
              ))}
            </div>

            {/* SKILLS */}
            <div>
              <h3 className='text-lg font-semibold text-black/70 mb-4'>
                Tech Stack
              </h3>

              <div className='flex flex-wrap gap-3'>
                {[
                  'React',
                  'Next.js',
                  'Node.js',
                  'Express',
                  'MySQL',
                  'MongoDB',
                  'Java',
                  'Tailwind',
                ].map((skill) => (
                  <span
                    key={skill}
                    className='
                    px-4 py-2 
                    border border-black/10 
                    rounded-full 
                    text-sm 
                    text-gray/700
                    hover:border-primary hover:text-primary
                    transition
                  '
                  >
                    {skill}
                  </span>
                ))}
              </div>
            </div>

            {/* CURRENT FOCUS */}
            <div>
              <h3 className='text-lg font-semibold text-black/70 mb-2'>
                Current Focus
              </h3>
              <p className='text-gray/600 text-sm leading-relaxed'>
                Building full-stack applications with API integration, improving
                backend performance, and strengthening Java fundamentals.
              </p>
            </div>
          </motion.div>
        </div>
      </section>
    </motion.div>
  );
}
